/* SQL ID : ScoreOverallDAO.selectOverallList 설 명 : */ WITH EXAM_ABSNET_T AS ( SELECT A.STD_ID , A.APRV_STSCD , A.TKEXAM_TYCD FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.EXAM_ID, A.STD_ID ORDER BY A.FRST_INQ_DTTM DESC) AS RN , A.STD_ID , A.APRV_STSCD , B.TKEXAM_TYCD FROM TB_LMS_EXAM_ABSNCE A JOIN TB_LMS_EXAM_BSC B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.EXAM_CTGRCD = 'EXAM' AND B.EXAM_TYCD = 'EXAM' AND B.TKEXAM_TYCD IN ('M', 'L') JOIN TB_LMS_EXAM_CRE_CRS_RLTN C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.SBJCT_ID = #{crsCreCd} WHERE A.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = C.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') ) A WHERE A.RN = 1 ), RE_EXAM_T AS ( SELECT A.STD_ID , B.TKEXAM_TYCD FROM TB_LMS_EXAM_STARE A JOIN TB_LMS_EXAM_BSC B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.EXAM_CTGRCD = 'EXAM' AND B.EXAM_TYCD = 'EXAM' AND B.TKEXAM_TYCD IN ('M', 'L') AND B.EXAM_SBST_REF_ID IS NOT NULL AND EXISTS ( SELECT 1 FROM TB_LMS_ASMT WHERE ASMT_ID = B.EXAM_SBST_REF_ID AND DELYN = 'N' UNION ALL SELECT 1 FROM TB_LMS_DSCS WHERE DSCS_ID = B.EXAM_SBST_REF_ID AND DELYN = 'N' UNION ALL SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_ID = B.EXAM_SBST_REF_ID AND DELYN = 'N' ) JOIN TB_LMS_EXAM_CRE_CRS_RLTN C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' AND A.REEXAMYN = 'Y' AND A.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = C.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') ), NO_EVAL_T AS (
), TEST_JOIN_T AS (
) SELECT ROW_NUMBER() OVER(ORDER BY XXX.USERNM ASC) AS LINE_NO , XXX.* FROM ( SELECT XX.* , (SELECT APRV_STSCD FROM EXAM_ABSNET_T WHERE STD_ID = XX.STD_ID AND TKEXAM_TYCD = 'M') AS APPR_STAT_M , (SELECT APRV_STSCD FROM EXAM_ABSNET_T WHERE STD_ID = XX.STD_ID AND TKEXAM_TYCD = 'L') AS APPR_STAT_L , CASE WHEN EXISTS(SELECT 1 FROM RE_EXAM_T WHERE STD_ID = XX.STD_ID AND TKEXAM_TYCD = 'M') THEN 'Y' ELSE 'N' END AS RE_EXAM_YN_M , CASE WHEN EXISTS(SELECT 1 FROM RE_EXAM_T WHERE STD_ID = XX.STD_ID AND TKEXAM_TYCD = 'L') THEN 'Y' ELSE 'N' END AS RE_EXAM_YN_L , (SELECT MID_NO_EVAL_CNT FROM NO_EVAL_T WHERE STD_ID = XX.STD_ID) AS MID_NO_EVAL_CNT , (SELECT LAST_NO_EVAL_CNT FROM NO_EVAL_T WHERE STD_ID = XX.STD_ID) AS LAST_NO_EVAL_CNT , (SELECT ASMNT_NO_EVAL_CNT FROM NO_EVAL_T WHERE STD_ID = XX.STD_ID) AS ASMNT_NO_EVAL_CNT , (SELECT FORUM_NO_EVAL_CNT FROM NO_EVAL_T WHERE STD_ID = XX.STD_ID) AS FORUM_NO_EVAL_CNT , (SELECT QUIZ_NO_EVAL_CNT FROM NO_EVAL_T WHERE STD_ID = XX.STD_ID) AS QUIZ_NO_EVAL_CNT , (SELECT TEST_NO_EVAL_CNT FROM NO_EVAL_T WHERE STD_ID = XX.STD_ID) AS TEST_NO_EVAL_CNT , (SELECT RESCH_NO_EVAL_CNT FROM NO_EVAL_T WHERE STD_ID = XX.STD_ID) AS RESCH_NO_EVAL_CNT , CASE WHEN EXISTS(SELECT 1 FROM TEST_JOIN_T WHERE STD_ID = XX.STD_ID AND TKEXAM_TYCD = 'M' AND JOIN_YN = 'N') AND XX.MIDDLE_TEST_SCORE <= 0 THEN 'Y' ELSE 'N' END AS MIDDLE_TEST_NO_YN , CASE WHEN EXISTS(SELECT 1 FROM TEST_JOIN_T WHERE STD_ID = XX.STD_ID AND TKEXAM_TYCD = 'L' AND JOIN_YN = 'N') AND XX.LAST_TEST_SCORE <= 0 THEN 'Y' ELSE 'N' END AS LAST_TEST_NO_YN FROM (
) XX ) XXX WHERE 1=1
AND (MID_NO_EVAL_CNT + LAST_NO_EVAL_CNT + ASMNT_NO_EVAL_CNT + FORUM_NO_EVAL_CNT + QUIZ_NO_EVAL_CNT + TEST_NO_EVAL_CNT + RESCH_NO_EVAL_CNT) > 0
AND ( ((LESSON_SCORE_AVG + MIDDLE_TEST_SCORE_AVG + LAST_TEST_SCORE_AVG + TEST_SCORE_AVG + ASSIGNMENT_SCORE_AVG + FORUM_SCORE_AVG + QUIZ_SCORE_AVG + RESH_SCORE_AVG) < 10) OR (MIDDLE_TEST_USE_YN = 'Y' AND LAST_TEST_USE_YN = 'Y' AND MIDDLE_TEST_NO_YN = 'Y' AND LAST_TEST_NO_YN = 'Y') OR (MIDDLE_TEST_USE_YN = 'Y' AND LAST_TEST_USE_YN = 'N' AND MIDDLE_TEST_NO_YN = 'Y') OR (MIDDLE_TEST_USE_YN = 'N' AND LAST_TEST_USE_YN = 'Y' AND LAST_TEST_NO_YN = 'Y') )

/* SQL ID : ScoreOverallDAO.selectOverallExcelList 설 명 : */ WITH TEST_JOIN_T AS (
) SELECT ROW_NUMBER() OVER(
ORDER BY ( SELECT A.ODR FROM (
SELECT #{item} AS USER_ID, #{index} AS ODR FROM DUAL
) A WHERE USER_ID = XX.USER_ID ), XX.USERNM
ORDER BY XX.USERNM
) AS LINE_NO , XX.* FROM ( SELECT X.* , CASE WHEN EXISTS(SELECT 1 FROM TEST_JOIN_T WHERE STD_ID = X.STD_ID AND TKEXAM_TYCD = 'M' AND JOIN_YN = 'N') AND X.MIDDLE_TEST_SCORE <= 0 THEN 'Y' ELSE 'N' END AS MIDDLE_TEST_NO_YN , CASE WHEN EXISTS(SELECT 1 FROM TEST_JOIN_T WHERE STD_ID = X.STD_ID AND TKEXAM_TYCD = 'L' AND JOIN_YN = 'N') AND X.LAST_TEST_SCORE <= 0 THEN 'Y' ELSE 'N' END AS LAST_TEST_NO_YN FROM (
) X ) XX WHERE 1=1
AND ( ((LESSON_SCORE_AVG + MIDDLE_TEST_SCORE_AVG + LAST_TEST_SCORE_AVG + TEST_SCORE_AVG + ASSIGNMENT_SCORE_AVG + FORUM_SCORE_AVG + QUIZ_SCORE_AVG + RESH_SCORE_AVG) < 10) OR (MIDDLE_TEST_USE_YN = 'Y' AND LAST_TEST_USE_YN = 'Y' AND MIDDLE_TEST_NO_YN = 'Y' AND LAST_TEST_NO_YN = 'Y') OR (MIDDLE_TEST_USE_YN = 'Y' AND LAST_TEST_USE_YN = 'N' AND MIDDLE_TEST_NO_YN = 'Y') OR (MIDDLE_TEST_USE_YN = 'N' AND LAST_TEST_USE_YN = 'Y' AND LAST_TEST_NO_YN = 'Y') )

/*
	 SQL ID : ScoreOverallDAO.selectOverallStdInfo
	 설  명 :
*/
SELECT X.*
FROM (

) X
WHERE 1=1


  		AND X.STD_ID = #{stdNo}


  		AND X.STD_ID = (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = #{crsCreCd} AND USER_ID = #{userId})

/* SQL ID : ScoreOverallDAO.selectMrksRankList 설 명 : 출결 F 대상 제외 순위목록 */ SELECT Y.* FROM ( SELECT XXX.SBJCT_ID , XXX.STD_ID , XXX.RNK , XXX.RNK_QUOTA , XXX.RNK_TRGTYN , RANK() OVER(ORDER BY IFNULL(XXX.CAL_TOT_SCR, 0) DESC) AS MARK_RANK , IFNULL(XXX.LESSON_SCORE_AVG, 0) AS LESSON_SCORE_AVG , IFNULL(XXX.MIDDLE_TEST_SCORE_AVG, 0) AS MIDDLE_TEST_SCORE_AVG , IFNULL(XXX.LAST_TEST_SCORE_AVG, 0) AS LAST_TEST_SCORE_AVG , IFNULL(XXX.TEST_SCORE_AVG, 0) AS TEST_SCORE_AVG , IFNULL(XXX.ASSIGNMENT_SCORE_AVG, 0) AS ASSIGNMENT_SCORE_AVG , IFNULL(XXX.FORUM_SCORE_AVG, 0) AS FORUM_SCORE_AVG , IFNULL(XXX.QUIZ_SCORE_AVG, 0) AS QUIZ_SCORE_AVG , IFNULL(XXX.RESH_SCORE_AVG, 0) AS RESH_SCORE_AVG , IFNULL(XXX.CAL_TOT_SCR, 0) AS CAL_TOT_SCR , IFNULL(XXX.CAL_TOT_SCR, 0) + IFNULL(XXX.ETC_SCORE, 0) AS FL_EXCH_SCR FROM ( SELECT XX.SBJCT_ID , XX.STD_ID , XX.RNK , XX.RNK_QUOTA , XX.RNK_TRGTYN , XX.LESSON_SCORE_AVG , XX.MIDDLE_TEST_SCORE_AVG , XX.LAST_TEST_SCORE_AVG , XX.TEST_SCORE_AVG , XX.ASSIGNMENT_SCORE_AVG , XX.FORUM_SCORE_AVG , XX.QUIZ_SCORE_AVG , XX.RESH_SCORE_AVG , XX.ETC_SCORE , ROUND(XX.LESSON_SCORE_AVG + XX.MIDDLE_TEST_SCORE_AVG + XX.LAST_TEST_SCORE_AVG + XX.TEST_SCORE_AVG + XX.ASSIGNMENT_SCORE_AVG + XX.FORUM_SCORE_AVG + XX.QUIZ_SCORE_AVG + XX.RESH_SCORE_AVG, 2) AS CAL_TOT_SCR FROM ( SELECT X.SBJCT_ID , X.STD_ID , X.RNK , X.RNK_QUOTA , X.RNK_TRGTYN , ROUND((CAST(X.LESSON_SCORE AS DECIMAL(5, 2))/100) * CAST(X.LESSON_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS LESSON_SCORE_AVG , ROUND((CAST(X.MIDDLE_TEST_SCORE AS DECIMAL(5, 2))/100) * CAST(X.MIDDLE_TEST_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS MIDDLE_TEST_SCORE_AVG , ROUND((CAST(X.LAST_TEST_SCORE AS DECIMAL(5, 2))/100) * CAST(X.LAST_TEST_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS LAST_TEST_SCORE_AVG , ROUND((CAST(X.TEST_SCORE AS DECIMAL(5, 2))/100) * CAST(X.TEST_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS TEST_SCORE_AVG , ROUND((CAST(X.ASSIGNMENT_SCORE AS DECIMAL(5, 2))/100) * CAST(X.ASSIGNMENT_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS ASSIGNMENT_SCORE_AVG , ROUND((CAST(X.FORUM_SCORE AS DECIMAL(5, 2))/100) * CAST(X.FORUM_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS FORUM_SCORE_AVG , ROUND((CAST(X.QUIZ_SCORE AS DECIMAL(5, 2))/100) * CAST(X.QUIZ_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS QUIZ_SCORE_AVG , ROUND((CAST(X.RESH_SCORE AS DECIMAL(5, 2))/100) * CAST(X.RESH_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS RESH_SCORE_AVG , ETC_SCORE FROM ( SELECT A.STD_ID , C.SBJCT_ID , A.RNK , A.RNK_QUOTA , A.RNK_TRGTYN , A.SCR_STSCD , A.SCR_GRDCD , ((SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID))) AS DEPTNM , (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID) AS USER_ID , ((SELECT X.USERNM FROM TB_LMS_USR X WHERE X.USER_ID = (SELECT XX.USER_ID FROM TB_LMS_ATNDLC_SBJCT XX WHERE XX.STD_ID = A.STD_ID))) AS USERNM , A.TOT_SCR , A.LST_SCR , A.ADTN_SCR AS ETC_SCORE , A.SCR_MEMO , MAX(IF(C.MRK_ITM_SEQ = '1', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS LESSON_SCORE , MAX(IF(C.MRK_ITM_SEQ = '1', C.MRK_RFLTRT , '-')) AS LESSON_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '1', B.SCR_ITM_ID, '-')) AS LESSON_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '2', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS MIDDLE_TEST_SCORE , MAX(IF(C.MRK_ITM_SEQ = '2', C.MRK_RFLTRT, '-')) AS MIDDLE_TEST_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '2', B.SCR_ITM_ID, '-')) AS MIDDLE_TEST_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '3', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS LAST_TEST_SCORE , MAX(IF(C.MRK_ITM_SEQ = '3', C.MRK_RFLTRT, '-')) AS LAST_TEST_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '3', B.SCR_ITM_ID, '-')) AS LAST_TEST_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '4', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS TEST_SCORE , MAX(IF(C.MRK_ITM_SEQ = '4', C.MRK_RFLTRT, '-')) AS TEST_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '4', B.SCR_ITM_ID, '-')) AS TEST_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '5', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS ASSIGNMENT_SCORE , MAX(IF(C.MRK_ITM_SEQ = '5', C.MRK_RFLTRT, '-')) AS ASSIGNMENT_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '5', B.SCR_ITM_ID, '-')) AS ASSIGNMENT_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '6', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS FORUM_SCORE , MAX(IF(C.MRK_ITM_SEQ = '6', C.MRK_RFLTRT, '-')) AS FORUM_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '6', B.SCR_ITM_ID, '-')) AS FORUM_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '7', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS QUIZ_SCORE , MAX(IF(C.MRK_ITM_SEQ = '7', C.MRK_RFLTRT, '-')) AS QUIZ_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '7', B.SCR_ITM_ID, '-')) AS QUIZ_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '8', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS RESH_SCORE , MAX(IF(C.MRK_ITM_SEQ = '8', C.MRK_RFLTRT, '-')) AS RESH_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '8', B.SCR_ITM_ID, '-')) AS RESH_ITEM_ID FROM TB_LMS_MRK_SBJCT A JOIN TB_LMS_STD_SCORE_ITEM B ON (B.STD_ID = A.STD_ID) JOIN TB_LMS_STD_SCORE_ITEM_CONF C ON (C.SCR_ITM_ID = B.SCR_ITM_ID) JOIN TB_LMS_ATNDLC_SBJCT D ON (D.STD_ID = A.STD_ID AND D.ATNDLC_STSCD = 'S' AND D.AUDITYN = 'N' AND D.SBJCT_ID = #{crsCreCd}) JOIN TB_LMS_USR E ON (D.USER_ID = E.USER_ID) WHERE E.SCHREG_GBN_CD IN ('01', '02', '20') GROUP BY A.STD_ID, C.SBJCT_ID ) X WHERE 1=1 AND X.SBJCT_ID = #{crsCreCd} ) XX
WHERE XX.LESSON_SCORE_AVG <> 0
) XXX ) Y

mapper.update:
/*
	 SQL ID : updateOverallScoreStatus
	 설  명 :
*/
UPDATE TB_LMS_MRK_SBJCT SET
	 SCR_STSCD = #{scoreStatus}
   , MDFR_ID = #{mdfrId}
   , MOD_DTTM = FN_DTTM()
WHERE STD_ID IN

	#{item.stdNo}

/*
	 SQL ID : updateTbLmsStdScoreItem
	 설  명 :
*/

UPDATE TB_LMS_STD_SCORE_ITEM SET
 	 ACQS_SCR = #{item.getScore}
   , MDFR_ID = #{item.mdfrId}
   , MOD_DTTM = FN_DTTM()
 WHERE STD_ID = #{item.stdNo}
   AND SCR_ITM_ID = #{item.scoreItemId}

/*
	 SQL ID : updateTbLmsStdScore
	 설  명 :
*/

UPDATE TB_LMS_MRK_SBJCT SET
 	 LST_SCR = #{item.finalScore}
   , ADTN_SCR = #{item.addScore}
   , MDFR_ID = #{item.mdfrId}
   , MOD_DTTM = FN_DTTM()
 WHERE STD_ID = #{item.stdNo}

/*
	 SQL ID : mergeScoreRel
	 설  명 :
*/
MERGE INTO TB_LMS_SBJCT_MRK_EVLRT T
USING( 
	SELECT #{crsCreCd} AS SBJCT_ID FROM DUAL
) S ON(T.SBJCT_ID = S.SBJCT_ID)
WHEN MATCHED THEN
	UPDATE SET
	    T.CALC_TYCD = #{calcType}
	  , T.RATIO_A1  = #{ratioA1}
	  , T.CNT_A1    = #{cntA1}
	  , T.RATIO_A2  = #{ratioA2}
	  , T.CNT_A2    = #{cntA2}
	  , T.RATIO_B1  = #{ratioB1}
	  , T.CNT_B1    = #{cntB1}
	  , T.RATIO_B2  = #{ratioB2}
	  , T.CNT_B2    = #{cntB2}
	  , T.RATIO_C1  = #{ratioC1}
	  , T.CNT_C1    = #{cntC1}
	  , T.RATIO_C2  = #{ratioC2}
	  , T.CNT_C2    = #{cntC2}
	  , T.RATIO_D1  = #{ratioD1}
	  , T.CNT_D1    = #{cntD1}
	  , T.RATIO_D2  = #{ratioD2}
	  , T.CNT_D2    = #{cntD2}
	  , T.RATIO_F   = #{ratioF}
	  , T.CNT_F     = #{cntF}
	  , T.MDFR_ID    = #{mdfrId}
	  , T.MOD_DTTM  = FN_DTTM()
WHEN NOT MATCHED THEN
	INSERT (
	SBJCT_ID
  , CALC_TYCD
  , RATIO_A1
  , CNT_A1
  , RATIO_A2
  , CNT_A2
  , RATIO_B1
  , CNT_B1
  , RATIO_B2
  , CNT_B2
  , RATIO_C1
  , CNT_C1
  , RATIO_C2
  , CNT_C2
  , RATIO_D1
  , CNT_D1
  , RATIO_D2
  , CNT_D2
  , RATIO_F
  , CNT_F
  , RGTR_ID
  , FRST_INQ_DTTM
  , MDFR_ID
  , MOD_DTTM
) VALUES (
	#{crsCreCd}
  , #{calcType}
  , NVL(#{ratioA1}, 0)
  , NVL(#{cntA1}, 0)
  , NVL(#{ratioA2}, 0)
  , NVL(#{cntA2}, 0)
  , NVL(#{ratioB1}, 0)
  , NVL(#{cntB1}, 0)
  , NVL(#{ratioB2}, 0)
  , NVL(#{cntB2}, 0)
  , NVL(#{ratioC1}, 0)
  , NVL(#{cntC1}, 0)
  , NVL(#{ratioC2}, 0)
  , NVL(#{cntC2}, 0)
  , NVL(#{ratioD1}, 0)
  , NVL(#{cntD1}, 0)
  , NVL(#{ratioD2}, 0)
  , NVL(#{cntD2}, 0)
  , NVL(#{ratioF}, 0)
  , NVL(#{cntF}, 0)
  , #{rgtrId}
  , FN_DTTM()
  , #{mdfrId}
  , FN_DTTM()
)

		/*
			 SQL ID : updateStdScoreGrade
			 설  명 :
		*/
		UPDATE TB_LMS_MRK_SBJCT
           SET TOT_SCR = #{totScore}
			  , SCR_GRDCD = #{scoreGrade}

			  , SCR_STSCD = #{scoreStatus}

			  , MDFR_ID = #{mdfrId}
			  , MOD_DTTM = FN_DTTM()
	     WHERE STD_ID = #{stdNo}

mapper.select:
/* SQL ID : selectOverallGraphList 설 명 : */
WITH SCORE_T AS ( SELECT 90.00 AS SP, 100 AS EP, '90.00~100' AS LABEL, 10 AS ODR FROM DUAL UNION ALL SELECT 80.00, 89.99, '80.00~89.99', 9 FROM DUAL UNION ALL SELECT 70.00, 79.99, '70.00~79.99', 8 FROM DUAL UNION ALL SELECT 60.00, 69.99, '60.00~69.99', 7 FROM DUAL UNION ALL SELECT 50.00, 59.99, '50.00~59.99', 6 FROM DUAL UNION ALL SELECT 40.00, 49.99, '40.00~49.99', 5 FROM DUAL UNION ALL SELECT 30.00, 39.99, '30.00~39.99', 4 FROM DUAL UNION ALL SELECT 20.00, 29.99, '20.00~29.99', 3 FROM DUAL UNION ALL SELECT 10.00, 19.99, '10.00~19.99', 2 FROM DUAL UNION ALL SELECT -1, 9.99, '0~9.99', 1 FROM DUAL ) SELECT T.LABEL AS LABEL, COUNT(DISTINCT A.STD_ID) AS CNT FROM SCORE_T T LEFT JOIN TB_LMS_MRK_SBJCT A ON 1 = 1 LEFT JOIN TB_LMS_STD_SCORE_ITEM B ON B.STD_ID = A.STD_ID LEFT JOIN TB_LMS_STD_SCORE_ITEM_CONF C ON C.SCR_ITM_ID = B.SCR_ITM_ID WHERE C.SBJCT_ID = #{crsCreCd}
AND NVL(A.LST_SCR, 0) BETWEEN T.SP AND T.EP
AND C.MRK_ITM_SEQ = #{selectType} AND NVL(B.ACQS_SCR, 0) BETWEEN T.SP AND T.EP
GROUP BY T.LABEL, T.ODR ORDER BY T.ODR DESC

/* SQL ID : selectOverallGraphList 설 명 : */ WITH SCORE_T AS ( SELECT 'A+' AS GRADE, 'A+' AS LABEL, 9 AS ODR FROM DUAL UNION ALL SELECT 'A', 'A', 8 FROM DUAL UNION ALL SELECT 'B+', 'B+', 7 FROM DUAL UNION ALL SELECT 'B', 'B', 6 FROM DUAL UNION ALL SELECT 'C+', 'C+', 5 FROM DUAL UNION ALL SELECT 'C', 'C', 4 FROM DUAL UNION ALL SELECT 'D+', 'D+', 3 FROM DUAL UNION ALL SELECT 'D', 'D', 2 FROM DUAL UNION ALL SELECT 'F', 'F', 1 FROM DUAL ), SCORE_CNT AS ( SELECT NVL(A.SCR_GRDCD, 'F') AS SCR_GRDCD, COUNT(DISTINCT A.STD_ID) AS CNT FROM TB_LMS_MRK_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON B.STD_ID = A.STD_ID WHERE B.SBJCT_ID = #{crsCreCd} AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' GROUP BY NVL(A.SCR_GRDCD, 'F') ) SELECT T.LABEL , NVL(S.CNT, 0) AS CNT FROM SCORE_T T LEFT JOIN SCORE_CNT S ON T.GRADE = S.SCR_GRDCD
WHERE T.ODR NOT IN (2, 3)
ORDER BY T.ODR DESC

/* SQL ID : selectOverallGridCase1 설 명 : */
SELECT ROUND ( AVG( ( SELECT X.LST_SCR FROM TB_LMS_MRK_SBJCT X WHERE X.STD_ID = A.STD_ID ) ) , 2) AS AVG_SCORE , MAX( ( SELECT X.LST_SCR FROM TB_LMS_MRK_SBJCT X WHERE X.STD_ID = A.STD_ID ) ) AS MAX_SCORE , MIN( ( SELECT X.LST_SCR FROM TB_LMS_MRK_SBJCT X WHERE X.STD_ID = A.STD_ID ) ) AS MIN_SCORE , COUNT(1) AS TOT_STD_CNT FROM TB_LMS_ATNDLC_SBJCT A WHERE A.SBJCT_ID = #{crsCreCd} AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N'
SELECT ROUND ( AVG( B.ACQS_SCR ) ,2) AS AVG_SCORE , MAX( B.ACQS_SCR ) AS MAX_SCORE , MIN( B.ACQS_SCR ) AS MIN_SCORE , COUNT(1) AS TOT_STD_CNT FROM TB_LMS_MRK_SBJCT A JOIN TB_LMS_STD_SCORE_ITEM B ON (B.STD_ID = A.STD_ID) JOIN TB_LMS_STD_SCORE_ITEM_CONF C ON (B.SCR_ITM_ID = C.SCR_ITM_ID) WHERE C.SBJCT_ID = #{crsCreCd} AND C.MRK_ITM_SEQ = #{selectType}

/* SQL ID : selectOverallGridCase2 설 명 : */
SELECT ROUND ( AVG(X.LST_SCR) ,2) AS AVG_10_SCORE FROM ( SELECT B.LST_SCR , (PERCENT_RANK() OVER (ORDER BY B.LST_SCR DESC) ) AS PER_RNK FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_MRK_SBJCT B ON (A.STD_ID = B.STD_ID) WHERE A.SBJCT_ID = #{crsCreCd} AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N' ) X WHERE X.PER_RNK <= 0.1
SELECT ROUND ( AVG(X.ACQS_SCR), 2) AS AVG_10_SCORE FROM ( SELECT B.ACQS_SCR , (PERCENT_RANK() OVER (ORDER BY B.ACQS_SCR DESC) ) AS PER_RNK FROM TB_LMS_MRK_SBJCT A JOIN TB_LMS_STD_SCORE_ITEM B ON (B.STD_ID = A.STD_ID) JOIN TB_LMS_STD_SCORE_ITEM_CONF C ON (B.SCR_ITM_ID = C.SCR_ITM_ID) WHERE C.SBJCT_ID = #{crsCreCd} AND C.MRK_ITM_SEQ = #{selectType}) X WHERE X.PER_RNK <= 0.1

