/* SQL ID : selectExamAbsentCnt 설 명 : */ SELECT COUNT(1) AS CNT FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.EXAM_ID, A.STD_ID ORDER BY A.FRST_INQ_DTTM DESC) AS RN , A.STD_ID , A.APRV_STSCD , B.TKEXAM_TYCD FROM TB_LMS_EXAM_ABSNCE A JOIN TB_LMS_EXAM_BSC B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.EXAM_CTGRCD = 'EXAM' AND B.EXAM_TYCD = 'EXAM' JOIN TB_LMS_EXAM_CRE_CRS_RLTN C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.SBJCT_ID = #{crsCreCd} WHERE A.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = C.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') ) A WHERE A.RN = 1 AND A.APRV_STSCD IN (
#{apprStats}
)
AND A.TKEXAM_TYCD = #{examStareTypeCd}

/* SQL ID : selectExamAbsent 설 명 : */ SELECT A.STD_ID FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.EXAM_ID, A.STD_ID ORDER BY A.FRST_INQ_DTTM DESC) AS RN , A.STD_ID , A.APRV_STSCD , B.TKEXAM_TYCD FROM TB_LMS_EXAM_ABSNCE A JOIN TB_LMS_EXAM_BSC B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.EXAM_CTGRCD = 'EXAM' AND B.EXAM_TYCD = 'EXAM' JOIN TB_LMS_EXAM_CRE_CRS_RLTN C ON A.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.SBJCT_ID = #{crsCreCd} WHERE A.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = C.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') ) A WHERE A.RN = 1 AND A.APRV_STSCD IN (
#{apprStats}
)
AND A.TKEXAM_TYCD = #{examStareTypeCd}

/*
	 SQL ID : selectSysJobSchCnt
	 설  명 :
*/
SELECT COUNT(1) AS CNT
  FROM (
		SELECT A.SYSJOB_SCHDL_SYMD  AS schStartDt
		     , A.SYSJOB_SCHDL_EYMD    AS schEndDt
		     , FN_DTTM() AS curDt
		  FROM TB_LMS_SYSJOB_SCHDL A
		 WHERE A.ORG_ID = #{orgId}
		   AND A.DGRS_YR = #{haksaYear}
		   AND A.DGRS_SMSTR = #{haksaTeam}
		   AND A.SYSJOB_SCHDL_TYCD = #{calendarCtgr}
		   AND A.USEYN = 'Y'
		) X
WHERE X.curDt >= X.schStartDt
  AND X.curDt <= X.schEndDt

