/* SQL ID : selectScoreObjtList 설 명 : */
SELECT X.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS LINE_NO , A.MRK_OBJCT_APLY_ID , A.SBJCT_ID , A.USER_ID -- , (SELECT DEPTNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = A.USER_ID)) AS DEPTNM -- , B.CRS_ID , B.SBJCTNM , B.DVCLAS_NO -- , B.SBJCT_ID , B.CRS_ID , A.OBJCT_APLYR_ID , (SELECT SCYR FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = A.USER_ID) AS SCYR , (SELECT X.USERNM FROM TB_LMS_USER_PRFIL X WHERE X.USER_PRFIL_ID = A.OBJCT_APLYR_ID) AS OBJT_USER_NM -- , (SELECT MOBILE_NO FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = A.OBJCT_APLYR_ID) AS USER_MOBILE_NO -- , (SELECT EMAIL FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = A.OBJCT_APLYR_ID) AS USER_EMAIL , A.OBJCT_APLY_CTS , A.OBJCT_APLY_DTTM , TO_CHAR(TO_DATE(A.OBJCT_APLY_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS OBJT_DTTM_FMT , A.CHGR_ID , (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = CHGR_ID) AS PROC_USER_NM -- SELECT * FROM TB_LMS_MRK_OBJCT_APLY , A.CHG_RSN , A.CHG_DTTM , TO_CHAR(TO_DATE(A.CHG_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS PROC_DTTM_FMT , A.CHG_PROC_CD , ( CASE WHEN A.CHG_PROC_CD = '1' THEN '승인(가산점부여)' WHEN A.CHG_PROC_CD = '2' THEN '확인(가산점미부여)' WHEN A.CHG_PROC_CD = '3' THEN '반려(가산점미부여)' ELSE '신청' END ) AS PROC_NM , ( CASE WHEN A.CHGR_ID IS NULL THEN 'N' ELSE 'Y' END) AS ANS_YN -- , NVL(( CASE WHEN A.CHGBFR_SCR IS NULL THEN C.TOT_SCR ELSE A.CHGBFR_SCR END ), 0) AS CHGBFR_SCR , NVL(( CASE WHEN A.CHGBFR_GRDCD IS NULL THEN C.SCR_GRDCD ELSE A.CHGBFR_GRDCD END ), 0) AS CHGBFR_GRDCD , NVL(A.CHGBFR_SCR, 0) AS CHGBFR_SCR -- , NVL(A.CHGBFR_GRDCD, 0) AS CHGBFR_GRDCD -- , B.UNIV_CD , (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = (SELECT USER_ID FROM TB_LMS_SBJCT_PROF WHERE PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y' AND SBJCT_ID = A.SBJCT_ID)) AS PROF_USER_NM , (SELECT USER_ID FROM TB_LMS_SBJCT_PROF WHERE PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y' AND SBJCT_ID = A.SBJCT_ID) AS PROF_USER_ID , (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = (SELECT USER_ID FROM TB_LMS_SBJCT_PROF WHERE PROF_TYCD = 'ASSISTANT' AND SBJCT_ID = A.SBJCT_ID AND ROWNUM = 1)) AS TUT_USER_NM , (SELECT USER_ID FROM TB_LMS_SBJCT_PROF WHERE PROF_TYCD = 'ASSISTANT' AND SBJCT_ID = A.SBJCT_ID) AS TUT_USER_ID FROM TB_LMS_MRK_OBJCT_APLY A JOIN TB_LMS_SBJCT B ON (B.SBJCT_ID = A.SBJCT_ID) LEFT OUTER JOIN TB_LMS_MRK_SBJCT C ON (C.USER_ID = A.USER_ID) WHERE 1=1
AND A.SBJCT_ID IN
#{item}
AND A.SBJCT_ID = #{crsCreCd}
AND A.OBJCT_APLYR_ID = #{userId}
AND A.CHG_PROC_CD #{procCd}
) X
WHERE ( X.DEPTNM LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR X.OBJCT_APLYR_ID LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR X.OBJT_USER_NM LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

