mapper.select:
/* SQL ID : selectScoreObjtListAdmin 설 명 : */ SELECT X.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.MRK_OBJCT_APLY_ID ASC) AS LINE_NO , G.USER_ID AS PROF_USER_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = G.USER_ID) AS PROF_USER_NM , (SELECT MOBILE_NO FROM TB_LMS_USR WHERE USER_ID = G.USER_ID) AS PROF_MOBILE_NO , (SELECT EMAIL FROM TB_LMS_USR WHERE USER_ID = G.USER_ID) AS PROF_EMAIL , A.MRK_OBJCT_APLY_ID , A.SBJCT_ID , A.STD_ID , F.DEPTNM , B.SBJCTNM , B.CRS_ID , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE DEPT_CD = B.DEPT_CD) AS MAIN_DEPT_NM , B.DVCLAS_NO , A.OBJCT_APLYR_ID , NVL(F.USER_GRADE, '-') AS USER_GRADE , F.USERNM AS OBJT_USER_NM , F.MOBILE_NO AS USER_MOBILE_NO , F.EMAIL AS USER_EMAIL , A.OBJCT_APLY_CTS , A.OBJCT_APLY_DTTM
, TO_CHAR(TO_DATE(A.OBJCT_APLY_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYYMMDDHH24MISS') AS OBJT_DTTM_FMT , A.CHGR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = CHGR_ID) AS PROC_USER_NM , (SELECT Z.USER_ID FROM SBJCT_PROF Z WHERE Z.SBJCT_ID = B.SBJCT_ID AND Z.PROF_TYCD = 'ASSISTANT' AND ROWNUM = 1) AS TUT_USER_ID , (SELECT (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = Z.USER_ID) FROM SBJCT_PROF Z WHERE Z.SBJCT_ID = B.SBJCT_ID AND Z.PROF_TYCD = 'ASSISTANT' AND ROWNUM = 1 ) AS TUT_USER_NM , A.CHG_RSN , A.CHG_DTTM
, TO_CHAR(TO_DATE(A.CHG_DTTM, 'YYYY-MM-DD HH24:MI:SS'), 'YYYYMMDDHH24MISS') AS PROC_DTTM_FMT , A.CHG_PROC_CD , ( CASE WHEN A.CHG_PROC_CD = '1' THEN '승인(가산점부여)' WHEN A.CHG_PROC_CD = '2' THEN '확인(가산점미부여)' WHEN A.CHG_PROC_CD = '3' THEN '반려(가산점미부여)' ELSE '신청' END ) AS PROC_NM , ( CASE WHEN A.CHGR_ID IS NULL THEN 'N' ELSE 'Y' END) AS ANS_YN , NVL(( CASE WHEN A.CHGBFR_SCR IS NULL THEN C.TOT_SCR ELSE A.CHGBFR_SCR END ), 0) AS CHGBFR_SCR , NVL(( CASE WHEN A.CHGBFR_GRDCD IS NULL THEN C.SCR_GRDCD ELSE A.CHGBFR_GRDCD END ), '-') AS CHGBFR_GRDCD , NVL(A.CHGBFR_SCR, 0) AS CHGBFR_SCR , NVL(A.CHGBFR_GRDCD, '-') AS CHGBFR_GRDCD , B.UNIV_CD , H.SCYR FROM MRK_OBJCT_APLY A JOIN TB_LMS_SBJCT B ON (B.SBJCT_ID = A.SBJCT_ID) LEFT OUTER JOIN TB_LMS_MRK_SBJCT C ON (C.STD_ID = A.STD_ID) JOIN TB_LMS_TERM_CRE_CRS_RLTN D ON (D.SBJCT_ID = B.SBJCT_ID) JOIN CRS_SMSTR E ON (E.CRS_SMSTR_ID = D.CRS_SMSTR_ID AND E.ORG_ID = #{orgId}) JOIN TB_LMS_USR F ON (F.USER_ID = A.OBJCT_APLYR_ID) JOIN SBJCT_PROF G ON (G.SBJCT_ID = B.SBJCT_ID AND G.RPRSYN = 'Y') JOIN TB_LMS_ATNDLC_SBJCT H ON A.STD_ID = H.STD_ID WHERE 1=1
AND E.DGRS_YR = #{haksaYear}
AND E.DGRS_SMSTR = #{haksaTerm}
AND E.CRS_SMSTR_ID = #{termCd}
AND B.UNIV_CD = #{uniCd}
AND F.DEPT_CD = #{deptCd}
AND B.SBJCT_ID = #{crsCreCd}
AND NVL(A.CHG_PROC_CD, '0') = #{procCd}
) X
WHERE ( X.DEPTNM LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR X.OBJCT_APLYR_ID LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR X.OBJT_USER_NM LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

/* SQL ID : selectStdScoreObjtList 설 명 : */ SELECT ROW_NUMBER() OVER(ORDER BY X.SBJCTNM DESC, X.DVCLAS_NO DESC) AS LINE_NO , X.* FROM ( SELECT A.ORG_ID , A.SBJCT_ID , B.SBJCTNM , B.CRS_ID , B.DVCLAS_NO , B.SBJCT_ID , B.CRS_ID , A.USER_ID , A.STD_ID , B.CRDTS , B.UNIV_CD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'CMCRS_GBNCD' AND CD = B.CMCRS_GBNCD) AS COMP_DV_NM , C.USER_ID AS TCH_USER_ID , (CASE WHEN C.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = C.USER_ID) END) AS TCH_USER_NM , C.SBJCT_ID AS TCH_CRS_CRE_CD , (SELECT X.SBJCTNM FROM TB_LMS_SBJCT X WHERE X.SBJCT_ID = C.SBJCT_ID) AS TCH_CRS_CRE_NM
, (SELECT TOT_SCR FROM TB_LMS_MRK_SBJCT WHERE STD_ID = A.STD_ID AND SCR_STSCD = '3') AS TOT_SCR , (SELECT SCR_GRDCD FROM TB_LMS_MRK_SBJCT WHERE STD_ID = A.STD_ID AND SCR_STSCD = '3') AS SCR_GRDCD , #{scoreSearchYn} AS scoreSearchYn
, '-' AS TOT_SCR , '-' AS SCR_GRDCD , #{scoreSearchYn} AS scoreSearchYn
, (SELECT SCR_STSCD FROM TB_LMS_MRK_SBJCT WHERE STD_ID = A.STD_ID AND SCR_STSCD = '3') AS SCR_STSCD , (SELECT MRK_OBJCT_APLY_ID FROM MRK_OBJCT_APLY WHERE STD_ID = A.STD_ID AND SBJCT_ID = A.SBJCT_ID) AS MRK_OBJCT_APLY_ID , (SELECT CHG_PROC_CD FROM MRK_OBJCT_APLY WHERE STD_ID = A.STD_ID AND SBJCT_ID = A.SBJCT_ID) AS CHG_PROC_CD FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_SBJCT B ON (A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND B.CRS_ID NOT LIKE '%JLPT%' AND B.SBJCT_TYCD = 'UNI') LEFT JOIN SBJCT_PROF C ON (C.SBJCT_ID = B.SBJCT_ID AND C.RPRSYN = 'Y') WHERE A.USER_ID = #{userId} AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N'
AND B.SBJCT_ID = #{creYear}
AND B.CRS_ID = #{creTerm}
AND B.SBJCT_TYCD = #{crsTypeCd}
) X

/* SQL ID : selectOverallStdInfoAdmin 설 명 : */ SELECT ROW_NUMBER() OVER() AS LINE_NO , X.STD_ID , X.CRS_SMSTR_ID , X.REATNDLCYN , IF(X.REATNDLCYN = 'Y', (SELECT SBJCT_ID FROM TB_LMS_SBJCT WHERE CRS_ID = X.CRS_ID AND SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = X.USER_ID) ORDER BY SBJCT_ID LIMIT 1), '-') AS SBJCT_ID , IF(X.REATNDLCYN = 'Y', (SELECT FN_GET_ORG_CODE_NM(X.ORG_ID, 'DGRS_SMSTR', CRS_ID) FROM TB_LMS_SBJCT WHERE CRS_ID = X.CRS_ID AND SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = X.USER_ID) ORDER BY SBJCT_ID LIMIT 1), '-') AS CRS_ID , IF(X.REATNDLCYN = 'Y', X.CRS_ID, '-') AS REPEAT_CRS_CD , X.CRS_ID , X.SBJCT_ID , X.SBJCTNM , X.DVCLAS_NO , X.CMCRS_GBNCD , X.COMP_DV_NM , X.CRDTS , X.REP_USER_NM , X.SCR_STSCD , X.SCR_GRDCD , X.DEPTNM , X.USER_ID , X.USERNM , X.USER_MOBILE_NO , X.USER_EMAIL , X.DRVTN_GRDCD , X.TOT_SCR , X.LST_SCR , X.LESSON_SCORE , X.LESSON_SCORE_RATIO , ROUND((CAST(X.LESSON_SCORE AS DECIMAL(5, 2))/100) * CAST(X.LESSON_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS LESSON_SCORE_AVG , X.LESSON_ITEM_ID , X.MIDDLE_TEST_SCORE , X.MIDDLE_TEST_SCORE_RATIO , ROUND((CAST(X.MIDDLE_TEST_SCORE AS DECIMAL(5, 2))/100) * CAST(X.MIDDLE_TEST_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS MIDDLE_TEST_SCORE_AVG , X.MIDDLE_TEST_ITEM_ID , X.LAST_TEST_SCORE , X.LAST_TEST_SCORE_RATIO , ROUND((CAST(X.LAST_TEST_SCORE AS DECIMAL(5, 2))/100) * CAST(X.LAST_TEST_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS LAST_TEST_SCORE_AVG , X.LAST_TEST_ITEM_ID , X.TEST_SCORE , X.TEST_SCORE_RATIO , ROUND((CAST(X.TEST_SCORE AS DECIMAL(5, 2))/100) * CAST(X.TEST_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS TEST_SCORE_AVG , X.TEST_ITEM_ID , X.ASSIGNMENT_SCORE , X.ASSIGNMENT_SCORE_RATIO , ROUND((CAST(X.ASSIGNMENT_SCORE AS DECIMAL(5, 2))/100) * CAST(X.ASSIGNMENT_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS ASSIGNMENT_SCORE_AVG , X.ASSIGNMENT_ITEM_ID , X.FORUM_SCORE , X.FORUM_SCORE_RATIO , ROUND((CAST(X.FORUM_SCORE AS DECIMAL(5, 2))/100) * CAST(X.FORUM_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS FORUM_SCORE_AVG , X.FORUM_ITEM_ID , X.QUIZ_SCORE , X.QUIZ_SCORE_RATIO , ROUND((CAST(X.QUIZ_SCORE AS DECIMAL(5, 2))/100) * CAST(X.QUIZ_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS QUIZ_SCORE_AVG , X.QUIZ_ITEM_ID , X.RESH_SCORE , X.RESH_SCORE_RATIO , ROUND((CAST(X.RESH_SCORE AS DECIMAL(5, 2))/100) * CAST(X.RESH_SCORE_RATIO AS DECIMAL(5, 2)), 2) AS RESH_SCORE_AVG , X.RESH_ITEM_ID , X.ETC_SCORE FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.TOT_SCR, A.LST_SCR ASC) AS LINE_NO , A.STD_ID , (SELECT ORG_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID) AS ORG_ID , (SELECT REATNDLCYN FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID) AS REATNDLCYN , E.CRS_SMSTR_ID , D.CRS_ID , C.SBJCT_ID , D.SBJCTNM , D.DVCLAS_NO , D.CMCRS_GBNCD , (SELECT CDNM FROM TB_SYS_CODE WHERE CTGRCD = 'COURSE_TYPE' AND CD = D.CMCRS_GBNCD) AS COMP_DV_NM , D.CRDTS , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE RPRSYN = 'Y' AND SBJCT_ID = C.SBJCT_ID)) AS REP_USER_NM , A.SCR_STSCD , A.SCR_GRDCD , (SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID)) AS DEPTNM , (SELECT USER_ID FROM TB_LMS_USR WHERE USER_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID)) AS USER_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID)) AS USERNM , (SELECT MOBILE_NO FROM TB_LMS_USR WHERE USER_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID)) AS USER_MOBILE_NO , (SELECT EMAIL FROM TB_LMS_USR WHERE USER_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID)) AS USER_EMAIL , A.DRVTN_GRDCD , A.TOT_SCR , A.LST_SCR , A.ADTN_SCR AS ETC_SCORE , MAX(IF(C.MRK_ITM_SEQ = '1', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS LESSON_SCORE , MAX(IF(C.MRK_ITM_SEQ = '1', C.MRK_RFLTRT , '-')) AS LESSON_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '1', B.SCR_ITM_ID, '-')) AS LESSON_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '2', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS MIDDLE_TEST_SCORE , MAX(IF(C.MRK_ITM_SEQ = '2', C.MRK_RFLTRT, '-')) AS MIDDLE_TEST_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '2', B.SCR_ITM_ID, '-')) AS MIDDLE_TEST_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '3', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS LAST_TEST_SCORE , MAX(IF(C.MRK_ITM_SEQ = '3', C.MRK_RFLTRT, '-')) AS LAST_TEST_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '3', B.SCR_ITM_ID, '-')) AS LAST_TEST_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '4', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS TEST_SCORE , MAX(IF(C.MRK_ITM_SEQ = '4', C.MRK_RFLTRT, '-')) AS TEST_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '4', B.SCR_ITM_ID, '-')) AS TEST_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '5', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS ASSIGNMENT_SCORE , MAX(IF(C.MRK_ITM_SEQ = '5', C.MRK_RFLTRT, '-')) AS ASSIGNMENT_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '5', B.SCR_ITM_ID, '-')) AS ASSIGNMENT_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '6', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS FORUM_SCORE , MAX(IF(C.MRK_ITM_SEQ = '6', C.MRK_RFLTRT, '-')) AS FORUM_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '6', B.SCR_ITM_ID, '-')) AS FORUM_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '7', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS QUIZ_SCORE , MAX(IF(C.MRK_ITM_SEQ = '7', C.MRK_RFLTRT, '-')) AS QUIZ_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '7', B.SCR_ITM_ID, '-')) AS QUIZ_ITEM_ID , MAX(IF(C.MRK_ITM_SEQ = '8', IF(B.ACQS_SCR < 0, 0, B.ACQS_SCR), '-')) AS RESH_SCORE , MAX(IF(C.MRK_ITM_SEQ = '8', C.MRK_RFLTRT, '-')) AS RESH_SCORE_RATIO , MAX(IF(C.MRK_ITM_SEQ = '8', B.SCR_ITM_ID, '-')) AS RESH_ITEM_ID FROM TB_LMS_MRK_SBJCT A JOIN TB_LMS_STD_SCORE_ITEM B ON (B.STD_ID = A.STD_ID) JOIN TB_LMS_STD_SCORE_ITEM_CONF C ON (C.SCR_ITM_ID = B.SCR_ITM_ID) JOIN TB_LMS_SBJCT D ON (D.SBJCT_ID = C.SBJCT_ID) JOIN TB_LMS_TERM_CRE_CRS_RLTN E ON (E.SBJCT_ID = D.SBJCT_ID) GROUP BY A.STD_ID, C.SBJCT_ID, E.CRS_SMSTR_ID ) X WHERE 1=1 AND X.USER_ID = #{userId} AND X.SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_SBJCT WHERE DELYN = 'N' AND SBJCT_ID = #{curYear} AND CRS_ID = #{curTerm}
AND UNIV_CD = #{uniCd}
)

/* SQL ID : selectErpTestScoreList 설 명 : */ SELECT A.* FROM ( SELECT YR , SMSTR_GBNCD , SBJCT_ID , DVCLAS_NO , STU_NO , INI_SCR1 , INI_SCR2 , INI_SCR3 , INI_SCR4 , INI_SCR5 , INI_SCR6 , INI_SCR7 , INI_SCR8 , INI_SCR9 , INI_SCR10 , INI_SCR11 , INI_SCR12 , INI_SCR13 , INI_SCR14 , (INI_SCR1 + INI_SCR2 + INI_SCR3 + INI_SCR4 + INI_SCR5 + INI_SCR6 + INI_SCR7 + INI_SCR8 + INI_SCR9 + INI_SCR10 + INI_SCR11 + INI_SCR12 + INI_SCR13 + INI_SCR14) AS INI_TOT_SCR , CAL_SCR1 , CAL_SCR2 , CAL_SCR3 , CAL_SCR4 , CAL_SCR5 , CAL_SCR6 , CAL_SCR7 , CAL_SCR8 , CAL_SCR9 , CAL_SCR10 , CAL_SCR11 , CAL_SCR12 , CAL_SCR13 , CAL_SCR14 , CAL_TOT_SCR , EXCH_SCR1 , EXCH_SCR2 , EXCH_SCR3 , EXCH_SCR4 , EXCH_SCR5 , EXCH_SCR6 , EXCH_SCR7 , EXCH_SCR8 , EXCH_SCR9 , EXCH_SCR10 , EXCH_SCR11 , EXCH_SCR12 , EXCH_SCR13 , EXCH_SCR14 , EXCH_TOT_SCR , CORR_SCR , FL_EXCH_SCR , MRKS_GRD_GBN , CASE WHEN MRKS_GRD_GBN = 'A+' THEN '4.5' WHEN MRKS_GRD_GBN = 'A' THEN '4.0' WHEN MRKS_GRD_GBN = 'B+' THEN '3.5' WHEN MRKS_GRD_GBN = 'B' THEN '3.0' WHEN MRKS_GRD_GBN = 'C+' THEN '2.5' WHEN MRKS_GRD_GBN = 'C' THEN '2.0' WHEN MRKS_GRD_GBN = 'D+' THEN '1.5' WHEN MRKS_GRD_GBN = 'D' THEN '1.0' WHEN MRKS_GRD_GBN = 'F' THEN '0.0' WHEN MRKS_GRD_GBN = 'P' THEN '0.0' END AS DRVTN_GRDCD , IF(MRK_EVL_TYCD = 'RELATIVE', '02', '03') AS MRKS_GRD_GV_GBN , IF(SCR_STSCD = '3', '1', '0') AS EXCH_YN , EXCH_GAP_SCR , IF(RNK_TRGTYN = 'Y', '1', '0') AS RNK_TRGTYN , IF(RNK_TRGTYN = 'Y', RNK, NULL) AS 'RANK' , IF(RNK_TRGTYN = 'Y', RNK_QUOTA, NULL) AS RNK_QUOTA , #{userId} AS INPT_ID , #{loginIp} AS INPT_IP , 'LMS' AS INPT_MENU_ID , #{userId} AS MOD_ID , #{loginIp} AS MOD_IP , 'LMS' AS MOD_MENU_ID FROM (
SELECT C.SBJCT_ID AS YR , C.CRS_ID AS SMSTR_GBNCD , C.CRS_ID AS SBJCT_ID , C.DVCLAS_NO AS DVCLAS_NO , B.USER_ID AS STU_NO -- 초기점수 , ( SELECT IF(ACQS_SCR < 0, 0, ACQS_SCR) FROM TB_LMS_STD_SCORE_ITEM AA JOIN TB_LMS_STD_SCORE_ITEM_CONF BB ON AA.SCR_ITM_ID = BB.SCR_ITM_ID AND BB.MRK_ITM_SEQ = '2' WHERE AA.STD_ID = A.STD_ID ) AS INI_SCR1 -- 중간 MIDDLE_TEST_SCORE , ( SELECT IF(ACQS_SCR < 0, 0, ACQS_SCR) FROM TB_LMS_STD_SCORE_ITEM AA JOIN TB_LMS_STD_SCORE_ITEM_CONF BB ON AA.SCR_ITM_ID = BB.SCR_ITM_ID AND BB.MRK_ITM_SEQ = '3' WHERE AA.STD_ID = A.STD_ID ) AS INI_SCR2 -- 기말 LAST_TEST_SCORE , ( SELECT IF(ACQS_SCR < 0, 0, ACQS_SCR) FROM TB_LMS_STD_SCORE_ITEM AA JOIN TB_LMS_STD_SCORE_ITEM_CONF BB ON AA.SCR_ITM_ID = BB.SCR_ITM_ID AND BB.MRK_ITM_SEQ = '5' WHERE AA.STD_ID = A.STD_ID ) AS INI_SCR3 -- 과제 ASSIGNMENT_SCORE , ( SELECT IF(ACQS_SCR < 0, 0, ACQS_SCR) FROM TB_LMS_STD_SCORE_ITEM AA JOIN TB_LMS_STD_SCORE_ITEM_CONF BB ON AA.SCR_ITM_ID = BB.SCR_ITM_ID AND BB.MRK_ITM_SEQ = '1' WHERE AA.STD_ID = A.STD_ID ) AS INI_SCR4 -- 과제 LESSON_SCORE , 0 AS INI_SCR5 , 0 AS INI_SCR6 , ( SELECT IF(ACQS_SCR < 0, 0, ACQS_SCR) FROM TB_LMS_STD_SCORE_ITEM AA JOIN TB_LMS_STD_SCORE_ITEM_CONF BB ON AA.SCR_ITM_ID = BB.SCR_ITM_ID AND BB.MRK_ITM_SEQ = '6' WHERE AA.STD_ID = A.STD_ID ) AS INI_SCR7 -- 토론 FORUM_SCORE , 0 AS INI_SCR8 , 0 AS INI_SCR9 , 0 AS INI_SCR10 , ( SELECT IF(ACQS_SCR < 0, 0, ACQS_SCR) FROM TB_LMS_STD_SCORE_ITEM AA JOIN TB_LMS_STD_SCORE_ITEM_CONF BB ON AA.SCR_ITM_ID = BB.SCR_ITM_ID AND BB.MRK_ITM_SEQ = '7' WHERE AA.STD_ID = A.STD_ID ) AS INI_SCR11 -- 퀴즈 QUIZ_SCORE , ( SELECT IF(ACQS_SCR < 0, 0, ACQS_SCR) FROM TB_LMS_STD_SCORE_ITEM AA JOIN TB_LMS_STD_SCORE_ITEM_CONF BB ON AA.SCR_ITM_ID = BB.SCR_ITM_ID AND BB.MRK_ITM_SEQ = '8' WHERE AA.STD_ID = A.STD_ID ) AS INI_SCR12 -- 설문 RESH_SCORE , ( SELECT IF(ACQS_SCR < 0, 0, ACQS_SCR) FROM TB_LMS_STD_SCORE_ITEM AA JOIN TB_LMS_STD_SCORE_ITEM_CONF BB ON AA.SCR_ITM_ID = BB.SCR_ITM_ID AND BB.MRK_ITM_SEQ = '4' WHERE AA.STD_ID = A.STD_ID ) AS INI_SCR13 -- 수시 TEST_SCORE , 0 AS INI_SCR14 -- 산출점수 , A.CAL_SCR_MID_TEST AS CAL_SCR1 , A.CAL_SCR_LAST_TEST AS CAL_SCR2 , A.CAL_SCR_ASMNT AS CAL_SCR3 , A.CNVS_SCR_LRN_PRGRT AS CAL_SCR4 , 0 AS CAL_SCR5 , 0 AS CAL_SCR6 , A.CAL_SCR_FORUM AS CAL_SCR7 , 0 AS CAL_SCR8 , 0 AS CAL_SCR9 , 0 AS CAL_SCR10 , A.CAL_SCR_QUIZ AS CAL_SCR11 , A.CAL_SCR_RESH AS CAL_SCR12 , A.CAL_SCR_TEST AS CAL_SCR13 , 0 AS CAL_SCR14 , A.CAL_TOT_SCR AS CAL_TOT_SCR -- 환산점수 , A.EXCH_SCR_MID_TEST AS EXCH_SCR1 , A.EXCH_SCR_LAST_TEST AS EXCH_SCR2 , A.EXCH_SCR_ASMNT AS EXCH_SCR3 , A.DRVTN_SCR_LRN_PRGRT AS EXCH_SCR4 , 0 AS EXCH_SCR5 , 0 AS EXCH_SCR6 , A.EXCH_SCR_FORUM AS EXCH_SCR7 , 0 AS EXCH_SCR8 , 0 AS EXCH_SCR9 , 0 AS EXCH_SCR10 , A.EXCH_SCR_QUIZ AS EXCH_SCR11 , A.EXCH_SCR_RESH AS EXCH_SCR12 , A.EXCH_SCR_TEST AS EXCH_SCR13 , 0 AS EXCH_SCR14 , A.EXCH_TOT_SCR AS EXCH_TOT_SCR , A.ADTN_SCR AS CORR_SCR , A.TOT_SCR AS FL_EXCH_SCR , A.SCR_GRDCD AS MRKS_GRD_GBN , A.DRVTN_GRDCD AS DRVTN_GRDCD , (SELECT MRK_EVL_TYCD FROM TB_LMS_CRE_CRS_EVAL WHERE SBJCT_ID = C.SBJCT_ID) AS MRK_EVL_TYCD , A.SCR_STSCD AS SCR_STSCD , A.EXCH_GAP_SCR AS EXCH_GAP_SCR , A.RNK_TRGTYN AS RNK_TRGTYN , A.RNK AS RNK , A.RNK_QUOTA AS RNK_QUOTA
FROM TB_LMS_MRK_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID AND B.ORG_ID = #{orgId} JOIN TB_LMS_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.DELYN = 'N'
AND C.SBJCT_ID = #{crsCreCd}
AND C.SBJCT_ID = #{creYear}
AND C.CRS_ID = #{creTerm}
AND C.CRS_ID NOT LIKE 'LEG%' AND C.CRS_ID NOT LIKE 'TEST%' GROUP BY C.SBJCT_ID, A.STD_ID ) A ) A

/* SQL ID : ScoreOverallDAO.selectOverallMainList 설 명 : */ SELECT A.CRS_ID , A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = B.ORG_ID) AS ORGNM -- , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = B.ORG_ID AND DEPT_CD = A.DEPT_CD) AS DEPTNM , A.CRDTS -- , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = B.ORG_ID AND CTGRCD = 'CMCRS_GBNCD' AND CD = A.CMCRS_GBNCD) AS COMP_DV_NM -- , NVL((SELECT SCR_STSCD FROM TB_LMS_MRK_SBJCT WHERE USER_ID = (SELECT MAX(USER_ID) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD ='S' AND AUDITYN = 'N')), 2) AS SCR_STSCD -- , (SELECT MRK_EVL_TYCD FROM TB_LMS_CRE_CRS_EVAL WHERE SBJCT_ID = A.SBJCT_ID) AS MRK_EVL_TYCD -- , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N') AS TOT_STD_CNT -- , A.UNIV_CD FROM TB_LMS_SBJCT A JOIN TB_LMS_CRS B ON A.CRS_ID = B.CRS_ID AND B.ORG_ID = #{orgId} JOIN TB_LMS_SBJCT_PROF C ON A.SBJCT_ID = C.SBJCT_ID AND C.USER_ID = #{userId} AND C.PROF_TYCD != 'MONITORING'
AND C.RPRSYN = 'Y'
WHERE A.DELYN = 'N' AND A.SBJCT_YR = #{creYear} AND A.SBJCT_SMSTR = #{creTerm} AND A.CRS_ID NOT LIKE '%JLPT%' AND A.SBJCT_TYCD = 'UNI' ORDER BY A.SBJCTNM, A.DVCLAS_NO

mapper.update:
/*
	 SQL ID : ScoreOverallDAO.updateScoreItemConfList
	 설  명 : 평가기준 수정
*/

UPDATE TB_LMS_STD_SCORE_ITEM_CONF
SET
	  MRK_RFLTRT = #{item.scoreRatio}
	, MDFR_ID = #{item.mdfrId}
	, MOD_DTTM = FN_DTTM()
WHERE SBJCT_ID = #{item.crsCreCd}
AND MRK_TYCD = #{item.scoreTypeCd}
